  ('esrs_G1_G1_5_02', 'esrs-g1-g1-5-02', 'Information about financial or in-kind political contributions', 'Concept', 'xbrli:stringItemType', 'duration', false, false, NULL),
  ('esrs_G1_G1_5_03', 'esrs-g1-g1-5-03', 'Financial political contributions made', 'Concept', 'xbrli:monetaryItemType', 'duration', true, true, 'iso4217:EUR'),
  ('esrs_G1_G1_5_04', 'esrs-g1-g1-5-04', 'Amount of internal and external lobbying expenses', 'Concept', 'xbrli:monetaryItemType', 'duration', true, true, 'iso4217:EUR'),
  ('esrs_G1_G1_5_05', 'esrs-g1-g1-5-05', 'Amount paid for membership to lobbying associations', 'Concept', 'xbrli:monetaryItemType', 'duration', true, true, 'iso4217:EUR'),
  ('esrs_G1_G1_5_06', 'esrs-g1-g1-5-06', 'In-kind political contributions made', 'Concept', 'xbrli:monetaryItemType', 'duration', true, true, 'iso4217:EUR'),
  ('esrs_G1_G1_5_07', 'esrs-g1-g1-5-07', 'Disclosure of how monetary value of in-kind contributions is estimated', 'Concept', 'xbrli:stringItemType', 'duration', false, false, NULL),
  ('esrs_G1_G1_5_08', 'esrs-g1-g1-5-08', 'Financial and in-kind political contributions made [table]', 'Concept', 'xbrli:stringItemType', 'duration', false, false, NULL),
  ('esrs_G1_G1_5_09', 'esrs-g1-g1-5-09', 'Disclosure of main topics covered by lobbying activities and undertaking''s main positions on these topics', 'Concept', 'xbrli:stringItemType', 'duration', false, false, NULL),
  ('esrs_G1_G1_5_10', 'esrs-g1-g1-5-10', 'Undertaking is registered in EU Transparency Register or in equivalent transparency register in Member State', 'Concept', 'xbrli:stringItemType', 'duration', false, false, NULL),
  ('esrs_G1_G1_5_11', 'esrs-g1-g1-5-11', 'Information about appointment of any members of administrative, management and supervisory bodies who held comparable position in public administration in two years preceding such appointment', 'Concept', 'xbrli:stringItemType', 'duration', false, false, NULL),
  ('esrs_G1_G1_5_12', 'esrs-g1-g1-5-12', 'The entity is legally obliged to be a member of a chamber of commerce or other organisation that represents its interests', 'Concept', 'xbrli:stringItemType', 'duration', false, false, NULL),
  ('esrs_G1_G1_13-14', 'esrs-g1-g1-13-14', 'Disclosures to be reported if the undertaking has not adopted actions', 'Concept', 'xbrli:stringItemType', 'duration', false, false, NULL),
  ('esrs_G1_G1_6_01', 'esrs-g1-g1-6-01', 'Average number of days to pay invoice from date when contractual or statutory term of payment starts to be calculated', 'Concept', 'xbrli:integerItemType', 'duration', false, false, NULL),
